import { useEffect, useRef, useState } from 'react'
import { Button } from '#/components/ui/button.tsx'

/**
 * Registers the Workbox service worker (generated by scripts/generate-sw.mjs)
 * and surfaces a reload prompt when a new version has been installed. Only runs
 * in production builds where /sw.js exists. Renders nothing until an update is
 * waiting.
 */
export function PwaUpdater() {
  const [waiting, setWaiting] = useState<ServiceWorker | null>(null)
  // Only reload on controllerchange that the user actually triggered — the
  // first-load clientsClaim also fires controllerchange and must be ignored.
  const userConfirmedRef = useRef(false)

  useEffect(() => {
    if (import.meta.env.DEV) return
    if (typeof navigator === 'undefined' || !('serviceWorker' in navigator)) {
      return
    }

    let cancelled = false

    navigator.serviceWorker
      .register('/sw.js', { scope: '/' })
      .then((reg) => {
        if (cancelled) return

        // A worker already waiting (updated in a previous session/tab).
        if (reg.waiting && navigator.serviceWorker.controller) {
          setWaiting(reg.waiting)
        }

        reg.addEventListener('updatefound', () => {
          const installing = reg.installing
          if (!installing) return
          installing.addEventListener('statechange', () => {
            // Installed + an existing controller ⇒ this is an update, not first install.
            if (
              installing.state === 'installed' &&
              navigator.serviceWorker.controller
            ) {
              setWaiting(reg.waiting ?? installing)
            }
          })
        })
      })
      .catch(() => {
        // No SW in dev or when unsupported — the app still works online.
      })

    // Reload once the user-activated worker takes control. Ignored on the
    // first-visit claim (userConfirmedRef is still false then).
    let reloading = false
    const onControllerChange = () => {
      if (!userConfirmedRef.current || reloading) return
      reloading = true
      window.location.reload()
    }
    navigator.serviceWorker.addEventListener(
      'controllerchange',
      onControllerChange,
    )

    return () => {
      cancelled = true
      navigator.serviceWorker.removeEventListener(
        'controllerchange',
        onControllerChange,
      )
    }
  }, [])

  if (!waiting) return null

  const reload = () => {
    // Ask the waiting worker to activate; controllerchange then reloads.
    userConfirmedRef.current = true
    waiting.postMessage({ type: 'SKIP_WAITING' })
  }

  return (
    <div
      role="status"
      className="surface-elevated fixed right-4 bottom-4 z-50 flex items-center gap-4 rounded-lg px-4 py-3"
      style={{ border: '1px solid var(--hairline-strong)' }}
    >
      <span className="text-body text-sm">A new version is available.</span>
      <Button size="sm" onClick={reload}>
        Reload
      </Button>
    </div>
  )
}
